/*@ Extern Coq (gcd_iterative_spec: Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import gcd_iterative */

int gcd_iterative(int a, int b)
/*@ Require
      0 <= a &&
      0 <= b &&
      0 < a + b &&
      emp
    Ensure
      gcd_iterative_spec(a@pre, b@pre, __return) && emp
*/
{
    int r;

    /*@ Inv exists g,
          0 <= a &&
          0 <= b &&
          0 < a@pre + b@pre &&
          gcd_iterative_spec(a@pre, b@pre, g) &&
          gcd_iterative_spec(a, b, g) &&
          emp
    */
    while (b != 0) {
        r = a % b;
        a = b;
        b = r;
    }

    return a;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (power_nonnegative_z: Z -> Z -> Z) */
/*@ Import Coq Require Import power_nonnegative */

int power_nonnegative(int base, int exp)
/*@ Require
      0 <= exp &&
      (forall (k: Z), (0 <= k && k <= exp) =>
        (INT_MIN <= power_nonnegative_z(base, k) &&
         power_nonnegative_z(base, k) <= INT_MAX)) &&
      emp
    Ensure
      __return == power_nonnegative_z(base@pre, exp@pre) && emp
*/
{
    int i;
    int ans = 1;

    /*@ Inv
          0 <= i && i <= exp &&
          base == base@pre &&
          exp == exp@pre &&
          ans == power_nonnegative_z(base, i) &&
          emp
    */
    for (i = 0; i < exp; ++i) {
        ans = ans * base;
    }

    return ans;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (digit_sum_z : Z -> Z) */
/*@ Import Coq Require Import digit_sum */

int digit_sum(int n)
/*@ Require
      0 <= n && n <= INT_MAX && emp
    Ensure
      __return == digit_sum_z(n@pre) && emp
*/
{
    int sum = 0;

    /*@ Inv
          0 <= n && n <= INT_MAX &&
          0 <= sum &&
          sum + n <= n@pre &&
          sum + digit_sum_z(n) == digit_sum_z(n@pre) &&
          emp
    */
    while (n > 0) {
        sum += n % 10;
        n = n / 10;
    }

    /*@ Assert
          n == 0 &&
          sum == digit_sum_z(n@pre) &&
          emp
    */
    return sum;
}

#include "../../verification_stdlib.h"

int sum_to_n(int n)
/*@ Require
      0 <= n &&
      INT_MIN <= n * (n + 1) / 2 &&
      n * (n + 1) / 2 <= INT_MAX &&
      emp
    Ensure
      __return == n@pre * (n@pre + 1) / 2 && emp
*/
{
    int i;
    int ret = 0;

    /*@ Inv
          1 <= i && i <= n + 1 &&
          n == n@pre &&
          ret == (i - 1) * i / 2
    */
    for (i = 1; i <= n; ++i) {
        ret += i;
    }

    /*@ Assert
          i == n + 1 &&
          n == n@pre &&
          ret == n * (n + 1) / 2
    */
    return ret;
}

